package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException, InstantiationException {
        // Given
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class,
                Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class, boolean.class, boolean.class,
                boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(',', '"', null, '#', '\\', false, true, "\r\n",
                "\\N", new Object[]{"Header"}, new String[]{"Name", "Age"}, false, false, false, true, false);

        // When
        boolean commentMarkerSet = csvFormat.isCommentMarkerSet();

        // Then
        assertTrue(commentMarkerSet);
    }
}
